import React, { useState, useEffect } from 'react';
import { Medicine } from '../types';
import { Pill, Plus, Trash2, Check, ShieldAlert, BellRing } from 'lucide-react';
import { Button } from './Button';
import { MedicineSafety } from './MedicineSafety';

interface Props {
  currentWeek?: number;
  isPostpartum?: boolean;
}

export const MedicineTracker: React.FC<Props> = ({ currentWeek = 1, isPostpartum = false }) => {
  const [activeTab, setActiveTab] = useState<'my-meds' | 'safety'>('my-meds');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [newMed, setNewMed] = useState({ name: '', time: '' });
  const [permission, setPermission] = useState(Notification.permission);

  const STORAGE_KEY = isPostpartum ? 'bloom_medicines_pp' : 'bloom_medicines_preg';

  // Load from Storage
  useEffect(() => {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) {
          setMedicines(JSON.parse(stored));
      } else {
          // Default data if empty
          const defaults: Medicine[] = isPostpartum ? [
            { id: '1', name: 'Calcium', dosage: '500mg', frequency: 'BD', time: '09:00', taken: false },
            { id: '2', name: 'Iron', dosage: '100mg', frequency: 'OD', time: '20:00', taken: false }
          ] : [
            { id: '1', name: 'Folic Acid', dosage: '5mg', frequency: 'Daily', time: '09:00', taken: false },
            { id: '2', name: 'Iron Supplement', dosage: '100mg', frequency: 'Daily', time: '20:00', taken: false }
          ];
          setMedicines(defaults);
          localStorage.setItem(STORAGE_KEY, JSON.stringify(defaults));
      }
  }, [STORAGE_KEY, isPostpartum]);

  // Save to Storage on Change
  useEffect(() => {
      if (medicines.length > 0) {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(medicines));
      }
  }, [medicines, STORAGE_KEY]);

  const requestNotificationPermission = () => {
      Notification.requestPermission().then(perm => {
          setPermission(perm);
          if (perm === 'granted') {
              new Notification("Reminders Enabled", { body: "Bloom will remind you to take your medicines." });
          }
      });
  };

  const toggleTaken = (id: string) => {
    const updated = medicines.map(m => m.id === id ? { ...m, taken: !m.taken } : m);
    setMedicines(updated);
  };

  const addMed = () => {
    if (newMed.name && newMed.time) {
      const updated = [...medicines, {
        id: Date.now().toString(),
        name: newMed.name,
        time: newMed.time,
        dosage: 'Check label',
        frequency: 'Daily',
        taken: false
      }];
      setMedicines(updated);
      setNewMed({ name: '', time: '' });
    }
  };

  const removeMed = (id: string) => {
    const updated = medicines.filter(m => m.id !== id);
    setMedicines(updated);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-10">
       <div className="flex gap-2 p-1 bg-gray-100 dark:bg-indigo-950/50 rounded-xl w-fit mx-auto mb-6">
          <button 
             onClick={() => setActiveTab('my-meds')}
             className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'my-meds' ? 'bg-white dark:bg-deep-card shadow text-teal-600 dark:text-teal-400' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
          >
             My Medicines
          </button>
          <button 
             onClick={() => setActiveTab('safety')}
             className={`px-6 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${activeTab === 'safety' ? 'bg-white dark:bg-deep-card shadow text-bloom-DEFAULT' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
          >
             <ShieldAlert size={16} /> {isPostpartum ? 'Lactation Safety' : 'Safety Guide'}
          </button>
       </div>

       {activeTab === 'my-meds' ? (
         <>
          <div className="bg-gradient-to-r from-teal-500 to-emerald-500 rounded-3xl p-8 text-white shadow-lg flex justify-between items-center">
              <div>
                  <h2 className="text-2xl font-bold mb-2">Medicine Cabinet</h2>
                  <p className="opacity-90">Keep track of your supplements and prescriptions.</p>
              </div>
              {permission !== 'granted' && (
                  <button onClick={requestNotificationPermission} className="bg-white/20 p-3 rounded-full hover:bg-white/30 backdrop-blur-md" title="Enable Alerts">
                      <BellRing size={24} />
                  </button>
              )}
          </div>

          <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 overflow-hidden">
              <div className="p-6 border-b border-gray-100 dark:border-indigo-800">
                <h3 className="font-bold text-gray-800 dark:text-white text-lg">Daily Checklist</h3>
              </div>

              <div className="divide-y divide-gray-100 dark:divide-indigo-800">
                {medicines.map(med => (
                  <div key={med.id} className={`p-4 flex items-center justify-between transition-colors ${med.taken ? 'bg-green-50/50 dark:bg-green-900/10' : 'hover:bg-gray-50 dark:hover:bg-indigo-900/20'}`}>
                      <div className="flex items-center gap-4">
                        <button 
                            onClick={() => toggleTaken(med.id)}
                            className={`w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${med.taken ? 'bg-green-500 border-green-500 text-white' : 'border-gray-300 dark:border-gray-600 text-transparent hover:border-green-500'}`}
                        >
                            <Check size={16} />
                        </button>
                        <div>
                            <p className={`font-medium text-lg ${med.taken ? 'text-gray-400 line-through' : 'text-gray-800 dark:text-white'}`}>
                                {med.name}
                            </p>
                            <p className="text-sm text-gray-500 dark:text-gray-400">
                                {med.time} • {med.dosage}
                            </p>
                        </div>
                      </div>
                      <button onClick={() => removeMed(med.id)} className="text-gray-400 hover:text-red-500 p-2">
                        <Trash2 size={18} />
                      </button>
                  </div>
                ))}

                {medicines.length === 0 && (
                    <div className="p-8 text-center text-gray-500">No medicines added yet.</div>
                )}
              </div>

              <div className="p-6 bg-gray-50 dark:bg-indigo-950/30">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Medicine Name</label>
                        <input 
                            type="text" 
                            value={newMed.name}
                            onChange={(e) => setNewMed({...newMed, name: e.target.value})}
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg dark:text-white dark:placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 text-gray-900"
                            placeholder="e.g. Calcium"
                        />
                    </div>
                    <div className="w-full md:w-40">
                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Time</label>
                        <input 
                            type="time" 
                            value={newMed.time}
                            onChange={(e) => setNewMed({...newMed, time: e.target.value})}
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-deep-bg dark:text-white focus:outline-none focus:ring-2 focus:ring-teal-500 text-gray-900"
                        />
                    </div>
                    <Button onClick={addMed} className="w-full md:w-auto bg-teal-500 hover:bg-teal-600 hover:shadow-teal-500/30">
                        <Plus size={20} /> Add
                    </Button>
                </div>
              </div>
          </div>
         </>
       ) : (
         <MedicineSafety currentWeek={currentWeek} isPostpartum={isPostpartum} />
       )}
    </div>
  );
};

import React, { useState } from 'react';
import { SAFETY_ITEMS } from '../safetyDatabase';
import { Search, CheckCircle2, AlertTriangle, XCircle, Filter } from 'lucide-react';
import { SafetyItem } from '../types';

export const SafetyDictionary: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeCategory, setActiveCategory] = useState<'All' | 'Food' | 'Beauty' | 'Activity' | 'Household'>('All');
  const [activeStatus, setActiveStatus] = useState<'All' | 'Safe' | 'Caution' | 'Avoid'>('All');

  const filteredItems = SAFETY_ITEMS.filter(item => {
    const matchesCategory = activeCategory === 'All' || item.category === activeCategory;
    const matchesStatus = activeStatus === 'All' || item.status === activeStatus;
    const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesCategory && matchesStatus && matchesSearch;
  });

  const getStatusColor = (status: SafetyItem['status']) => {
    switch(status) {
      case 'Safe': return 'border-green-200 bg-green-50 dark:bg-green-900/10 dark:border-green-900/30';
      case 'Caution': return 'border-yellow-200 bg-yellow-50 dark:bg-yellow-900/10 dark:border-yellow-900/30';
      case 'Avoid': return 'border-red-200 bg-red-50 dark:bg-red-900/10 dark:border-red-900/30';
    }
  };

  const getStatusIcon = (status: SafetyItem['status']) => {
    switch(status) {
      case 'Safe': return <CheckCircle2 className="text-green-600 dark:text-green-400" size={20} />;
      case 'Caution': return <AlertTriangle className="text-yellow-600 dark:text-yellow-400" size={20} />;
      case 'Avoid': return <XCircle className="text-red-600 dark:text-red-400" size={20} />;
    }
  };

  const categories = ['All', 'Food', 'Beauty', 'Activity', 'Household'];
  const statuses = ['All', 'Safe', 'Caution', 'Avoid'];

  return (
    <div className="space-y-6 animate-fade-in">

      {/* Header & Search */}
      <div className="bg-gradient-to-r from-teal-500 to-cyan-600 rounded-3xl p-8 text-white shadow-lg">
         <h2 className="text-2xl font-bold mb-2 flex items-center gap-2">
            <CheckCircle2 /> Is It Safe?
         </h2>
         <p className="opacity-90 mb-6">Instantly check safety of 300+ foods, products, and activities.</p>

         <div className="relative">
            <input 
              type="text" 
              placeholder="Search e.g. 'Sushi', 'Retinol', 'Yoga'..." 
              className="w-full pl-12 pr-4 py-4 rounded-xl text-gray-900 dark:text-white bg-white/95 dark:bg-black/40 backdrop-blur-sm border-none shadow-lg focus:ring-2 focus:ring-white/50 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
         </div>
      </div>

      {/* Categories */}
      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
         {categories.map(cat => (
            <button
               key={cat}
               onClick={() => setActiveCategory(cat as any)}
               className={`px-5 py-2 rounded-full text-sm font-bold whitespace-nowrap transition-all ${
                  activeCategory === cat 
                    ? 'bg-teal-600 text-white shadow-md' 
                    : 'bg-white dark:bg-deep-card text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-indigo-900/30 border border-gray-200 dark:border-indigo-800'
               }`}
            >
               {cat}
            </button>
         ))}
      </div>

      {/* Status Filter */}
      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
         {statuses.map(stat => (
            <button
               key={stat}
               onClick={() => setActiveStatus(stat as any)}
               className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${
                  activeStatus === stat 
                    ? 'bg-gray-800 text-white border-gray-800 dark:bg-white dark:text-gray-900' 
                    : 'bg-transparent text-gray-500 border-gray-300 dark:border-gray-700'
               }`}
            >
               {stat}
            </button>
         ))}
      </div>

      {/* Grid Results */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filteredItems.length > 0 ? (
             filteredItems.map(item => (
                <div key={item.id} className={`p-4 rounded-2xl border transition-all hover:shadow-md ${getStatusColor(item.status)}`}>
                    <div className="flex items-start justify-between mb-2">
                       <h3 className="font-bold text-gray-900 dark:text-white">{item.name}</h3>
                       {getStatusIcon(item.status)}
                    </div>
                    <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider mb-2 ${
                        item.status === 'Safe' ? 'bg-green-200 text-green-800 dark:bg-green-800 dark:text-green-200' :
                        item.status === 'Caution' ? 'bg-yellow-200 text-yellow-800 dark:bg-yellow-800 dark:text-yellow-200' :
                        'bg-red-200 text-red-800 dark:bg-red-800 dark:text-red-200'
                    }`}>
                        {item.status}
                    </span>
                    <p className="text-sm text-gray-700 dark:text-gray-300 leading-snug">
                       {item.reason}
                    </p>
                </div>
             ))
          ) : (
             <div className="col-span-full text-center py-12 text-gray-400">
                 <p>No items found matching criteria.</p>
             </div>
          )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { UserSettings, WeightLog, BPLog, GlucoseLog, PregnancyCalculations, BabyGrowthLog, LabLog } from '../types';
import { WEIGHT_GAIN_GUIDELINES, BP_THRESHOLDS, GLUCOSE_THRESHOLDS, WHO_GROWTH_DATA, IAP_GROWTH_GUIDELINES, LAB_THRESHOLDS } from '../constants';
import { Button } from './Button';
import { Scale, Activity, HeartPulse, Droplet, Plus, Trash2, TrendingUp, AlertCircle, Baby, Ruler, Zap, Info, FileDown, X, Eye, ExternalLink, FileText, FlaskConical } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface Props {
  settings: UserSettings;
  calculations: PregnancyCalculations;
}

export const HealthTracker: React.FC<Props> = ({ settings, calculations }) => {
  const isPostpartum = settings.isPostpartum;

  const [activeTab, setActiveTab] = useState<'weight' | 'vitals'>('weight'); // Re-using 'weight' for Baby Growth in Postpartum
  const [chartType, setChartType] = useState<'weight' | 'length'>('weight'); // Switch for WHO charts

  // -- States --
  // Maternal Weight
  const [weightLogs, setWeightLogs] = useState<WeightLog[]>([]);
  const [newWeight, setNewWeight] = useState('');

  // Baby Growth
  const [growthLogs, setGrowthLogs] = useState<BabyGrowthLog[]>([]);
  const [newGrowth, setNewGrowth] = useState({ weight: '', height: '', head: '', waist: '' });

  // Vitals
  const [bpLogs, setBpLogs] = useState<BPLog[]>([]);
  const [glucoseLogs, setGlucoseLogs] = useState<GlucoseLog[]>([]);

  // New Vitals
  const [tshLogs, setTshLogs] = useState<LabLog[]>([]);
  const [hbLogs, setHbLogs] = useState<LabLog[]>([]);
  const [hba1cLogs, setHba1cLogs] = useState<LabLog[]>([]);

  const [newBP, setNewBP] = useState({ sys: '', dia: '' });
  const [newGlucose, setNewGlucose] = useState({ type: 'fasting' as 'fasting' | 'post_prandial' | 'random', value: '' });
  const [newLab, setNewLab] = useState({ tsh: '', hb: '', hba1c: '' });

  // PDF Preview State
  const [pdfPreviewUrl, setPdfPreviewUrl] = useState<string | null>(null);

  // Dynamic Storage Keys based on Mode
  const STORAGE_KEYS = {
      weight: isPostpartum ? 'bloom_pp_weight_logs' : 'bloom_weight_logs',
      bp: isPostpartum ? 'bloom_pp_bp_logs' : 'bloom_bp_logs',
      glucose: isPostpartum ? 'bloom_pp_glucose_logs' : 'bloom_glucose_logs',
      tsh: isPostpartum ? 'bloom_pp_tsh_logs' : 'bloom_tsh_logs',
      hb: isPostpartum ? 'bloom_pp_hb_logs' : 'bloom_hb_logs',
      hba1c: isPostpartum ? 'bloom_pp_hba1c_logs' : 'bloom_hba1c_logs',
      babyGrowth: 'bloom_baby_growth'
  };

  // Load Data
  useEffect(() => {
    const load = (key: string, setter: any) => {
        const saved = localStorage.getItem(key);
        if (saved) setter(JSON.parse(saved));
        else setter([]);
    };

    load(STORAGE_KEYS.weight, setWeightLogs);
    load(STORAGE_KEYS.bp, setBpLogs);
    load(STORAGE_KEYS.glucose, setGlucoseLogs);
    load(STORAGE_KEYS.tsh, setTshLogs);
    load(STORAGE_KEYS.hb, setHbLogs);
    load(STORAGE_KEYS.hba1c, setHba1cLogs);
    load(STORAGE_KEYS.babyGrowth, setGrowthLogs);
  }, [isPostpartum]); // Reload when switching modes

  // -- Helper Functions --

  const calculateBMI = (weight: number) => {
    if (settings.heightCm && weight) {
      const heightM = settings.heightCm / 100;
      return (weight / (heightM * heightM)).toFixed(1);
    }
    return "N/A";
  };

  const getLatestWeight = () => {
      if(weightLogs.length > 0) {
          return weightLogs[weightLogs.length - 1].weight;
      }
      return settings.prePregnancyWeight || 0;
  };

  const getWeightGuidelines = () => {
    const startWeight = settings.prePregnancyWeight || 60; // fallback
    const bmiVal = parseFloat(calculateBMI(startWeight));

    if (isNaN(bmiVal)) return WEIGHT_GAIN_GUIDELINES.normal;

    if (bmiVal < 18.5) return WEIGHT_GAIN_GUIDELINES.underweight;
    if (bmiVal >= 25 && bmiVal < 30) return WEIGHT_GAIN_GUIDELINES.overweight;
    if (bmiVal >= 30) return WEIGHT_GAIN_GUIDELINES.obese;
    return WEIGHT_GAIN_GUIDELINES.normal;
  };

  const getBabyAgeWeeks = () => {
      if (!settings.birthDate) return 0;
      const birth = new Date(settings.birthDate);
      const now = new Date();
      return Math.floor((now.getTime() - birth.getTime()) / (1000 * 60 * 60 * 24 * 7));
  };

  const addWeightLog = () => {
    if (!newWeight) return;
    const log: WeightLog = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      week: calculations.currentWeek, // Or weeks postpartum
      weight: parseFloat(newWeight)
    };
    const updated = [...weightLogs, log].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
    setWeightLogs(updated);
    localStorage.setItem(STORAGE_KEYS.weight, JSON.stringify(updated));
    setNewWeight('');
  };

  const deleteWeightLog = (id: string) => {
      const updated = weightLogs.filter(w => w.id !== id);
      setWeightLogs(updated);
      localStorage.setItem(STORAGE_KEYS.weight, JSON.stringify(updated));
  };

  const addGrowthLog = () => {
      if(!newGrowth.weight) return;
      const log: BabyGrowthLog = {
          id: Date.now().toString(),
          date: new Date().toISOString(),
          weekAge: getBabyAgeWeeks(),
          weight: parseFloat(newGrowth.weight),
          height: parseFloat(newGrowth.height) || 0,
          headCirc: parseFloat(newGrowth.head) || 0,
          waistCirc: parseFloat(newGrowth.waist) || 0
      };
      const updated = [...growthLogs, log].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
      setGrowthLogs(updated);
      localStorage.setItem(STORAGE_KEYS.babyGrowth, JSON.stringify(updated));
      setNewGrowth({ weight: '', height: '', head: '', waist: '' });
  };

  const deleteGrowthLog = (id: string) => {
      const updated = growthLogs.filter(g => g.id !== id);
      setGrowthLogs(updated);
      localStorage.setItem(STORAGE_KEYS.babyGrowth, JSON.stringify(updated));
  };

  const addBP = () => {
    if (!newBP.sys || !newBP.dia) return;
    const log: BPLog = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      systolic: parseInt(newBP.sys),
      diastolic: parseInt(newBP.dia)
    };
    const updated = [log, ...bpLogs];
    setBpLogs(updated);
    localStorage.setItem(STORAGE_KEYS.bp, JSON.stringify(updated));
    setNewBP({ sys: '', dia: '' });
  };

  const addGlucose = () => {
    if (!newGlucose.value) return;
    const log: GlucoseLog = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      type: newGlucose.type,
      value: parseInt(newGlucose.value)
    };
    const updated = [log, ...glucoseLogs];
    setGlucoseLogs(updated);
    localStorage.setItem(STORAGE_KEYS.glucose, JSON.stringify(updated));
    setNewGlucose({ ...newGlucose, value: '' });
  };

  const addLabLog = (type: 'tsh' | 'hb' | 'hba1c') => {
      const val = newLab[type];
      if (!val) return;

      const log: LabLog = {
          id: Date.now().toString(),
          date: new Date().toISOString(),
          value: parseFloat(val),
          unit: type === 'tsh' ? 'mIU/L' : type === 'hb' ? 'g/dL' : '%'
      };

      let updated;
      if (type === 'tsh') { updated = [log, ...tshLogs]; setTshLogs(updated); localStorage.setItem(STORAGE_KEYS.tsh, JSON.stringify(updated)); }
      if (type === 'hb') { updated = [log, ...hbLogs]; setHbLogs(updated); localStorage.setItem(STORAGE_KEYS.hb, JSON.stringify(updated)); }
      if (type === 'hba1c') { updated = [log, ...hba1cLogs]; setHba1cLogs(updated); localStorage.setItem(STORAGE_KEYS.hba1c, JSON.stringify(updated)); }

      setNewLab({ ...newLab, [type]: '' });
  };

  const getBPStatus = (sys: number, dia: number) => {
    if (sys >= 140 || dia >= 90) return BP_THRESHOLDS.high;
    if (sys >= 130 || dia >= 80) return BP_THRESHOLDS.elevated;
    return BP_THRESHOLDS.normal;
  };

  const getGlucoseStatus = (type: string, val: number) => {
      if (type === 'fasting' && val > 95) return { label: 'High (>95)', color: 'text-red-600' };
      if (type === 'post_prandial' && val > 120) return { label: 'High (>120)', color: 'text-red-600' };
      if (type === 'random' && val > 140) return { label: 'High (>140)', color: 'text-red-600' };
      return { label: 'Normal', color: 'text-green-600' };
  };

  const getLabStatus = (type: 'tsh' | 'hb' | 'hba1c', val: number) => {
      if (type === 'tsh') {
          // FOGSI Guidelines
          const t1 = LAB_THRESHOLDS.tsh.pregnant_t1;
          const t2t3 = LAB_THRESHOLDS.tsh.pregnant_t2_t3;

          if (!settings.isPostpartum) {
              const trimester = calculations.trimester;
              if (trimester === 1) {
                  if (val < t1.min) return { label: 'Low', color: 'text-red-600' };
                  if (val > t1.max) return { label: 'High (>2.5)', color: 'text-red-600' };
              } else {
                  if (val < t2t3.min) return { label: 'Low', color: 'text-red-600' };
                  if (val > t2t3.max) return { label: 'High (>3.0)', color: 'text-red-600' };
              }
          }
          if (val > 4.0) return { label: 'Hypothyroid', color: 'text-red-600' };
      }

      if (type === 'hb') {
          const limit = settings.isPostpartum ? 10 : 11;
          if (val < 7) return { label: 'Severe Anemia', color: 'text-red-600 font-bold' };
          if (val < limit) return { label: 'Anemia', color: 'text-orange-600' };
      }

      if (type === 'hba1c') {
          const limit = settings.isPostpartum ? 5.7 : 6.0;
          if (val > limit) return { label: 'High', color: 'text-red-600' };
      }

      return { label: 'Normal', color: 'text-green-600' };
  };

  const handlePreviewPdf = () => {
      try {
        const doc = generatePdfDoc();
        const blob = doc.output('blob');
        const url = URL.createObjectURL(blob);
        setPdfPreviewUrl(url);
      } catch (e) {
        console.error("PDF Gen Error", e);
        alert("Could not generate PDF preview. Please try downloading directly.");
      }
  };

  const handleDownloadPdf = () => {
      const doc = generatePdfDoc();
      doc.save('bloom_health_report.pdf');
      setPdfPreviewUrl(null); 
  };

  const renderLabInput = (
      title: string, 
      field: 'tsh' | 'hb' | 'hba1c', 
      logs: LabLog[], 
      unit: string, 
      guideline: { label: string }
  ) => {
      return (
          <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
              <h4 className="font-bold text-gray-800 dark:text-white mb-4 flex gap-2 items-center">
                  <FlaskConical size={18} className="text-teal-600" /> {title}
              </h4>
              <p className="text-xs text-gray-500 mb-2 font-medium bg-gray-50 dark:bg-indigo-900/20 p-2 rounded">
                  Guide: {guideline.label}
              </p>

              {/* Changed Layout: Input + Button in one row like Glucose */}
              <div className="flex flex-col gap-2 mb-4">
                  <div className="flex gap-2">
                      <input 
                          type="number" 
                          placeholder={`Value (${unit})`} 
                          className="flex-1 px-4 py-2 rounded-lg border border-gray-200 dark:border-indigo-700 bg-white dark:bg-indigo-950/50 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-teal-500"
                          value={newLab[field]}
                          onChange={(e) => setNewLab({...newLab, [field]: e.target.value})}
                      />
                  </div>
                  <Button onClick={() => addLabLog(field)} className="w-full">Add Log</Button>
              </div>

              <div className="space-y-2 max-h-40 overflow-y-auto pr-1 custom-scrollbar">
                  {logs.map(log => {
                      const status = getLabStatus(field, log.value);
                      return (
                          <div key={log.id} className="p-3 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border border-gray-100 dark:border-indigo-900/30 flex justify-between items-center">
