          bandPathBottom += (i === 0 ? "M" : " L") + `${x},${yScale(p.sd2neg)}`;
      });
      const bandShape = `${bandPathTop} L${xScale(data[data.length-1].week)},${yScale(data[data.length-1].sd2neg)} ` + data.slice().reverse().map((p: any) => `L${xScale(p.week)},${yScale(p.sd2neg)}`).join(' ') + " Z";
