import { PostpartumDashboard } from './components/PostpartumDashboard';
import { PrePregnancyDashboard } from './components/PrePregnancyDashboard';
import { Timeline } from './components/Timeline';
import { ReportAnalyzer } from './components/ReportAnalyzer';
import { MedicineTracker } from './components/MedicineTracker';
import { Profile } from './components/Profile';
import { DietPlan } from './components/DietPlan';
import { VaccinationTracker } from './components/VaccinationTracker';
import { ToolsHub } from './components/ToolsHub';
import { HealthTracker } from './components/HealthTracker';
import { Login } from './components/Login';
import { LayoutDashboard, Calendar, FileText, Pill, Moon, Sun, Settings, User, Utensils, Syringe, Baby, Wrench, HeartPulse, LogOut, Users, PlusCircle } from 'lucide-react';

const PROFILE_SPECIFIC_KEYS = [
  'bloom_kicks',
  'bloom_contractions',
  'bloom_milestones',
  'bloom_weight_logs',
  'bloom_pp_weight_logs',
  'bloom_bp_logs',
  'bloom_pp_bp_logs',
  'bloom_glucose_logs',
  'bloom_pp_glucose_logs',
  'bloom_baby_growth',
  'bloom_tsh_logs', 'bloom_pp_tsh_logs',
  'bloom_hb_logs', 'bloom_pp_hb_logs',
  'bloom_hba1c_logs', 'bloom_pp_hba1c_logs',
  'bloom_medicines_preg', 'bloom_medicines_pp' // Added medicine keys here too for profile switching
];

export default function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [settings, setSettings] = useState<UserSettings | null>(null);
  const [activeTab, setActiveTab] = useState<TabView>(TabView.DASHBOARD);

  // Profile Management State
  const [profiles, setProfiles] = useState<ProfileMeta[]>([]);
  const [showProfileSwitcher, setShowProfileSwitcher] = useState(false);

  // Global Notification Check
  useEffect(() => {
      const checkMedicines = () => {
          if (!settings) return;
          const key = settings.isPostpartum ? 'bloom_medicines_pp' : 'bloom_medicines_preg';
          const stored = localStorage.getItem(key);
          if (stored) {
              const meds = JSON.parse(stored);
              const now = new Date();
              const currentHour = now.getHours();
              const currentMin = now.getMinutes();

              meds.forEach((m: any) => {
                  const [h, min] = m.time.split(':').map(Number);
                  // Check if time matches current time (within the minute) and not taken
                  if (h === currentHour && Math.abs(min - currentMin) < 1 && !m.taken) {
                      if (Notification.permission === 'granted') {
                          new Notification(`Medicine Reminder: ${m.name}`, {
                              body: `Time to take ${m.name} (${m.dosage}).`,
                              icon: '/icon.png' // Fallback icon
                          });
                      }
                  }
              });
          }
      };

      const interval = setInterval(checkMedicines, 60000); // Check every minute
      return () => clearInterval(interval);
  }, [settings]); // Re-run effect if settings/profile changes

  // Load auth & settings & profile meta
  useEffect(() => {
    const auth = localStorage.getItem('bloom_auth');
    if (auth === 'true') {
      setIsAuthenticated(true);
    }

    const savedSettings = localStorage.getItem('bloom_settings');
    const savedProfiles = localStorage.getItem('bloom_all_profiles');

    if (savedSettings) {
      const parsed = JSON.parse(savedSettings);

      // Legacy Migration: If no ID, assign one and create profile meta
      if (!parsed.id) {
          parsed.id = 'default_profile_' + Date.now();
          localStorage.setItem('bloom_settings', JSON.stringify(parsed));
      }

      // Default field migrations for older data
      if (!parsed.status) parsed.status = parsed.isPostpartum ? 'postpartum' : 'pregnant';
      if (!parsed.comorbidities) parsed.comorbidities = [];
      if (!parsed.dietaryPreference) parsed.dietaryPreference = 'vegetarian';
      if (parsed.lactoseIntolerant === undefined) parsed.lactoseIntolerant = false;
      if (!parsed.vaccinationsDone) parsed.vaccinationsDone = [];
      if (!parsed.preConceptionChecklist) parsed.preConceptionChecklist = [];
      if (!parsed.periodLog) parsed.periodLog = [];
      if (parsed.pregnancyLmp === undefined) parsed.pregnancyLmp = null;
      if (!parsed.maternalBloodGroup) parsed.maternalBloodGroup = '';

      // Migration for new Risk Features (Obstetric History & Age)
      if (!parsed.obstetricHistory) {
          parsed.obstetricHistory = {
              gravida: 1,
              para: 0,
              abortions: 0,
              abortionsT1: 0,
              abortionsT2: 0,
              living: 0,
              lastBabyCongenitalDefect: false
          };
      }
      if (parsed.age === undefined) parsed.age = 0; 

      setSettings(parsed);

      // Initialize Profiles List
      if (savedProfiles) {
          setProfiles(JSON.parse(savedProfiles));
      } else {
          // Create initial profile list from current settings
          const initialProfile: ProfileMeta = {
              id: parsed.id,
              name: parsed.name,
              status: parsed.status,
              babyName: parsed.babyName,
              babyGender: parsed.babyGender,
              birthDate: parsed.birthDate,
              lastActive: new Date().toISOString()
          };
          setProfiles([initialProfile]);
          localStorage.setItem('bloom_all_profiles', JSON.stringify([initialProfile]));
      }
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // --- Profile Switching Logic ---

  const handleSwitchProfile = (targetProfileId: string) => {
      if (!settings || settings.id === targetProfileId) return;

      // 1. Snapshot Current Profile Data
      // Save current active logs into namespaced keys (e.g. bloom_kicks_profile_1)
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = localStorage.getItem(key);
          if (data) {
              localStorage.setItem(`${key}_${settings.id}`, data);
          } else {
              localStorage.removeItem(`${key}_${settings.id}`);
          }
      });
      // Save current settings to namespaced key
      localStorage.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      // 2. Hydrate Target Profile Data
      // Load target profile logs into active keys
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const savedData = localStorage.getItem(`${key}_${targetProfileId}`);
          if (savedData) {
              localStorage.setItem(key, savedData);
          } else {
              localStorage.removeItem(key); // Clear if no data for target
          }
      });

      // 3. Load Target Settings
      const targetSettingsRaw = localStorage.getItem(`bloom_settings_${targetProfileId}`);
      if (targetSettingsRaw) {
          const targetSettings = JSON.parse(targetSettingsRaw);
          setSettings(targetSettings);
          localStorage.setItem('bloom_settings', targetSettingsRaw); // Set as active settings

          // Update Meta Last Active
          const updatedProfiles = profiles.map(p => 
              p.id === targetProfileId ? { ...p, lastActive: new Date().toISOString() } : p
          );
          setProfiles(updatedProfiles);
          localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

          // Refresh to ensure all sub-components read new localStorage values
          window.location.reload(); 
      }
  };

  const handleAddProfile = () => {
      if (!settings) return;

      // 1. Snapshot Current Data (Same as switch)
      PROFILE_SPECIFIC_KEYS.forEach(key => {
          const data = localStorage.getItem(key);
          if (data) localStorage.setItem(`${key}_${settings.id}`, data);
          else localStorage.removeItem(`${key}_${settings.id}`);
      });
      localStorage.setItem(`bloom_settings_${settings.id}`, JSON.stringify(settings));

      // 2. Create New Settings (Inherit Shared Data)
      const newId = `profile_${Date.now()}`;
      const newSettings: UserSettings = {
          id: newId,
          name: settings.name, // Mom's name is shared
          status: 'planning', // Default to planning for new journey
          lmp: null,
          cycleLength: settings.cycleLength,

          // Shared Stats (Don't make mom re-enter)
          heightCm: settings.heightCm,
          prePregnancyWeight: settings.prePregnancyWeight, // Might change, but good default
          maternalBloodGroup: settings.maternalBloodGroup,
          paternalBloodGroup: settings.paternalBloodGroup,
          paternalHeightCm: settings.paternalHeightCm,
          obstetricHistory: settings.obstetricHistory, // Copy history
          comorbidities: settings.comorbidities, // Usually persistent
          dietaryPreference: settings.dietaryPreference,
          lactoseIntolerant: settings.lactoseIntolerant,
          age: settings.age,

          // Reset Logs for new baby
          periodLog: [],
          vaccinationsDone: [],
          isPostpartum: false,
          preConceptionChecklist: []
      };

      // 3. Clear Active Keys for fresh start
      PROFILE_SPECIFIC_KEYS.forEach(key => localStorage.removeItem(key));

      // 4. Update State & Storage
      setSettings(newSettings);
      localStorage.setItem('bloom_settings', JSON.stringify(newSettings));

      const newProfileMeta: ProfileMeta = {
          id: newId,
          name: newSettings.name,
          status: 'planning',
          babyName: undefined,
          lastActive: new Date().toISOString()
      };

      const updatedProfiles = [...profiles, newProfileMeta];
      setProfiles(updatedProfiles);
      localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));

      // Force reload to apply clean state
      window.location.reload();
  };

  const calculations: PregnancyCalculations | null = useMemo(() => {
    if (!settings || !settings.lmp) return null;

    const lmpDate = new Date(settings.lmp);
    const now = new Date();
    const diffTime = Math.abs(now.getTime() - lmpDate.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    // Logic: Naegele's rule adjusted
    const cycleAdjustment = settings.cycleLength - 28;
    const edd = new Date(lmpDate);
    edd.setDate(edd.getDate() + 280 + cycleAdjustment);

    const weeks = Math.floor(diffDays / 7);
    const days = diffDays % 7;

    let trimester: 1 | 2 | 3 = 1;
    if (weeks > 13) trimester = 2;
    if (weeks > 27) trimester = 3;

    return {
      edd,
      currentWeek: weeks === 0 ? 1 : weeks, // Minimum week 1
      currentDay: days,
      totalDays: diffDays,
      trimester,
      month: Math.ceil(weeks / 4.3),
      progressPercent: Math.min((diffDays / 280) * 100, 100)
    };
  }, [settings]);

  // Determine App Mode based on Settings Status
  const isPostpartum = settings?.status === 'postpartum';
  const isPlanning = settings?.status === 'planning';
  const isPregnant = settings?.status === 'pregnant';

  // Dynamic Theme Logic (Strict Gender Colors for Postpartum)
  let themeColor = 'text-pink-600';
  let activeBg = 'bg-pink-600 text-white shadow-pink-500/30';
  let bgGradient = 'bg-gradient-to-r from-pink-600 to-purple-600';
  let badgeColor = 'bg-pink-100 text-pink-600';

  if (isPlanning) {
      themeColor = 'text-teal-600';
      activeBg = 'bg-teal-600 text-white shadow-teal-500/30';
      bgGradient = 'bg-gradient-to-r from-teal-500 to-emerald-600';
      badgeColor = 'bg-teal-100 text-teal-600';
  } else if (isPostpartum) {
      if (settings?.babyGender === 'boy') {
          themeColor = 'text-blue-600';
          activeBg = 'bg-blue-600 text-white shadow-blue-500/30';
          bgGradient = 'bg-gradient-to-r from-blue-600 to-cyan-600';
          badgeColor = 'bg-blue-100 text-blue-600';
      } else {
          // Explicit Pink for Girl (Postpartum) to differ from Pregnancy Purple/Pink mix
          themeColor = 'text-rose-500';
          activeBg = 'bg-rose-500 text-white shadow-rose-500/30';
          bgGradient = 'bg-gradient-to-r from-rose-400 to-pink-500';
          badgeColor = 'bg-rose-100 text-rose-600';
      }
  }

  const getBabyAgeInWeeks = () => {
    if (!settings?.birthDate) return 0;
    const birth = new Date(settings.birthDate);
    const now = new Date();
    const diff = Math.abs(now.getTime() - birth.getTime());
    return Math.floor(diff / (1000 * 60 * 60 * 24 * 7));
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
    localStorage.setItem('bloom_auth', 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('bloom_auth');
    setActiveTab(TabView.DASHBOARD);
  };

  const handleOnboardingComplete = (data: UserSettings) => {
    // Inject ID if missing from Onboarding
    if (!data.id) data.id = 'profile_' + Date.now();

    // Initial sync of log if date provided
    if (data.lmp) {
        data.periodLog = [data.lmp];
        data.pregnancyLmp = data.status === 'pregnant' ? data.lmp : null;
    }

    // Ensure new fields are initialized
    if (!data.obstetricHistory) {
        data.obstetricHistory = {
            gravida: 1,
            para: 0,
            abortions: 0,
            abortionsT1: 0,
            abortionsT2: 0,
            living: 0,
            lastBabyCongenitalDefect: false
        };
    }
    if (data.age === undefined) data.age = 0;

    setSettings(data);
    localStorage.setItem('bloom_settings', JSON.stringify(data));

    // Initialize Profiles List for new user
    const meta: ProfileMeta = {
        id: data.id,
        name: data.name,
        status: data.status,
        babyName: data.babyName,
        babyGender: data.babyGender,
        birthDate: data.birthDate,
        lastActive: new Date().toISOString()
    };
    setProfiles([meta]);
    localStorage.setItem('bloom_all_profiles', JSON.stringify([meta]));
  };

  const handleUpdateProfile = (data: UserSettings) => {
    setSettings(data);
    localStorage.setItem('bloom_settings', JSON.stringify(data));

    // Update Meta in Profile List
    const updatedProfiles = profiles.map(p => 
        p.id === data.id ? { 
            ...p, 
            name: data.name, 
            status: data.status, 
            babyName: data.babyName,
            babyGender: data.babyGender,
            birthDate: data.birthDate
        } : p
    );
    setProfiles(updatedProfiles);
    localStorage.setItem('bloom_all_profiles', JSON.stringify(updatedProfiles));
  };

  const handleVaccineUpdate = (vaxId: string) => {
    if (!settings) return;
    const currentDone = settings.vaccinationsDone || [];
    let newDone;
    if (currentDone.includes(vaxId)) {
        newDone = currentDone.filter(id => id !== vaxId);
    } else {
        newDone = [...currentDone, vaxId];
    }
    const newSettings = { ...settings, vaccinationsDone: newDone };
    setSettings(newSettings);
    localStorage.setItem('bloom_settings', JSON.stringify(newSettings));
  };

  const handleReset = () => {
    localStorage.clear();
    setTimeout(() => {
        window.location.reload();
    }, 50);
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  if (!settings) {
    return (
      <>
        <div className="fixed top-4 right-4 z-50">
           <button onClick={() => setDarkMode(!darkMode)} className="p-3 rounded-full bg-white dark:bg-deep-card shadow-lg text-bloom-DEFAULT dark:text-yellow-400">
             {darkMode ? <Sun size={20} /> : <Moon size={20} />}
           </button>
        </div>
        <Onboarding onComplete={handleOnboardingComplete} />
      </>
    );
  }

  // Determine Nav Items
  let navItems = [];

  if (isPlanning) {
      navItems = [
          { id: TabView.DASHBOARD, icon: Calendar, label: 'Cycle & Plan' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Body Ready' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.TOOLS, icon: Wrench, label: 'Tools' }
      ];
  } else if (isPostpartum) {
      navItems = [
          { id: TabView.DASHBOARD, icon: Baby, label: 'Baby Care' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Growth & Vitals' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.VACCINATIONS, icon: Syringe, label: 'Vaccines' }, 
          { id: TabView.DIET, icon: Utensils, label: 'Mom Diet' }
      ];
  } else {
      // Pregnant
      navItems = [
          { id: TabView.DASHBOARD, icon: LayoutDashboard, label: 'Dashboard' },
          { id: TabView.HEALTH, icon: HeartPulse, label: 'Vitals' },
          { id: TabView.TOOLS, icon: Wrench, label: 'Tools' },
          { id: TabView.TIMELINE, icon: Calendar, label: 'Timeline' },
          { id: TabView.MEDICINES, icon: Pill, label: 'Meds' },
          { id: TabView.DIET, icon: Utensils, label: 'Diet Plan' },
          { id: TabView.VACCINATIONS, icon: Syringe, label: 'Vaccines' },
          { id: TabView.REPORTS, icon: FileText, label: 'Reports' },
      ];
  }

  const renderContent = () => {
    const calcSafe = calculations || { 
        currentWeek: 0, edd: new Date(), currentDay: 0, totalDays: 0, trimester: 1, month: 1, progressPercent: 0 
    } as PregnancyCalculations;

    const profileKey = settings.id;

    switch(activeTab) {
      case TabView.DASHBOARD: 
        if (isPlanning) return <PrePregnancyDashboard key={`plan_${profileKey}`} settings={settings} onUpdateSettings={handleUpdateProfile} />;
        if (isPostpartum) return <PostpartumDashboard key={`pp_${profileKey}`} settings={settings} />;
        return <Dashboard key={`preg_${profileKey}`} calculations={calcSafe} settings={settings} />;

      case TabView.TIMELINE: return <Timeline key={`time_${profileKey}`} calculations={calcSafe} settings={settings} />;
      case TabView.REPORTS: return <ReportAnalyzer key={`rep_${profileKey}`} />;
      case TabView.MEDICINES: return <MedicineTracker key={`med_${profileKey}`} currentWeek={calcSafe.currentWeek} isPostpartum={isPostpartum} />;
      case TabView.DIET: return <DietPlan key={`diet_${profileKey}`} settings={settings} calculations={calcSafe} />;
      case TabView.VACCINATIONS: 
        return <VaccinationTracker 
            key={`vax_${profileKey}`}
            settings={settings} 
            currentWeek={isPostpartum ? getBabyAgeInWeeks() : calcSafe.currentWeek} 
            onUpdate={handleVaccineUpdate} 
        />;
      case TabView.HEALTH: return <HealthTracker key={`health_${profileKey}`} settings={settings} calculations={calcSafe} />;
      case TabView.TOOLS: return <ToolsHub key={`tools_${profileKey}`} />;
      case TabView.PROFILE: 
        return <Profile 
            key={`prof_${profileKey}`}
            settings={settings} 
            profiles={profiles} 
            onUpdate={handleUpdateProfile} 
            onReset={handleReset} 
            onAddProfile={handleAddProfile}
            onSwitchProfile={handleSwitchProfile}
        />;
      default: return null;
    }
  };

  return (
    <div className="flex h-screen w-full overflow-hidden bg-bloom-light dark:bg-deep-bg transition-colors duration-300">

      {/* Sidebar - Desktop */}
      <aside className="hidden md:flex w-64 flex-col bg-white dark:bg-deep-card border-r border-gray-200 dark:border-deep-border shrink-0 h-full">
         <div className="p-6">
             <h1 className={`text-2xl font-bold bg-clip-text text-transparent ${bgGradient}`}>
                {isPlanning ? "Bloom Plan" : isPostpartum ? (settings.babyGender === 'boy' ? "Bloom Baby" : "Bloom Baby") : "Bloom Bump"}
             </h1>
             {profiles.length > 1 && (
                 <div className="mt-2 flex items-center gap-2 cursor-pointer" onClick={() => setActiveTab(TabView.PROFILE)}>
                     <div className="flex -space-x-2">
                         {profiles.slice(0, 3).map(p => (
                             <div key={p.id} className="w-6 h-6 rounded-full border border-white bg-gray-200 flex items-center justify-center text-[10px] overflow-hidden">
                                 {p.babyName ? p.babyName[0] : p.name[0]}
                             </div>
                         ))}
                     </div>
                     <span className="text-xs text-gray-500 underline">Switch Profile</span>
                 </div>
             )}
         </div>

         <nav className="flex-1 p-4 space-y-2 overflow-y-auto custom-scrollbar">
            {navItems.map(item => (
               <button
                 key={item.id}
                 onClick={() => setActiveTab(item.id)}
                 className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all font-medium ${activeTab === item.id ? `${activeBg} shadow-lg` : 'text-gray-700 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}
               >
                  <item.icon size={20} />
                  {item.label}
               </button>
            ))}
         </nav>

         <div className="p-4 border-t border-gray-200 dark:border-deep-border mt-auto">
            <div 
              onClick={() => setActiveTab(TabView.PROFILE)}
              className="flex items-center gap-3 px-4 py-3 rounded-xl bg-gray-100 dark:bg-slate-800/50 mb-2 cursor-pointer hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors"
            >
                <div className={`w-8 h-8 rounded-full ${badgeColor} flex items-center justify-center font-bold`}>
                    {settings.name.charAt(0).toUpperCase()}
                </div>
                <div className="flex-1 overflow-hidden">
                    <p className="text-sm font-bold truncate text-gray-800 dark:text-white">{settings.babyName || settings.name}</p>
                    <p className="text-xs text-gray-500 truncate capitalize">
                        {settings.status === 'postpartum' && settings.babyName ? 'Baby Profile' : settings.status}
                    </p>
                </div>
                <Settings size={16} className="text-gray-400" />
            </div>
            <button 
              onClick={handleLogout}
              className="w-full flex items-center gap-2 px-4 py-2 text-sm text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
            >
              <LogOut size={16} /> Sign Out
            </button>
         </div>
      </aside>

      {/* Mobile Nav - Fixed Bottom */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-deep-card border-t border-gray-200 dark:border-deep-border z-50 flex flex-col safe-area-bottom shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
         <div className="flex items-center gap-1 overflow-x-auto px-2 py-2 w-full no-scrollbar">
            {[
              ...navItems,
              { id: TabView.PROFILE, icon: User, label: 'Profile' },
            ].map(item => (
               <button
                 key={item.id}
                 onClick={() => setActiveTab(item.id)}
                 className={`flex-shrink-0 flex flex-col items-center gap-1 p-2 rounded-xl transition-all min-w-[64px] ${activeTab === item.id ? themeColor : 'text-gray-400'}`}
               >
                  <item.icon size={22} />
                  <span className="text-[10px] font-medium whitespace-nowrap">{item.label}</span>
               </button>
            ))}
         </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
         <header className="h-16 flex items-center justify-between px-4 md:px-8 border-b border-gray-200 dark:border-deep-border bg-white/50 dark:bg-deep-card/50 backdrop-blur-md sticky top-0 z-40 shrink-0">
            <div className="flex items-center gap-2">
                <h2 className="text-lg md:text-xl font-bold text-gray-800 dark:text-white capitalize truncate">
                    {activeTab === TabView.VACCINATIONS ? 'Vaccinations' : activeTab.replace('-', ' ')}
                </h2>
                {profiles.length > 1 && (
                    <span className="text-xs px-2 py-0.5 rounded-full bg-gray-100 dark:bg-slate-800 text-gray-500 dark:text-gray-400 border border-gray-200 dark:border-slate-700 hidden md:inline-block">
                        Active: {settings.babyName || "Profile 1"}
                    </span>
                )}
            </div>
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 rounded-full bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-gray-600 dark:text-yellow-400 transition-colors shadow-sm"
            >
              {darkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
         </header>

         <div className="flex-1 overflow-y-auto overflow-x-hidden p-4 md:p-8 pb-28 md:pb-8 custom-scrollbar scroll-smooth w-full">
            <div className="max-w-7xl mx-auto w-full">
              {renderContent()}
            </div>
         </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { UserSettings } from '../types';
import { PRE_CONCEPTION_CHECKLIST, PRE_CONCEPTION_COMORBIDITY_GUIDELINES, OBSTETRIC_HISTORY_RISKS, DAILY_TIPS_REGISTRY } from '../constants';
import { Button } from './Button';
import { Calendar, Droplet, Heart, CheckCircle2, Circle, AlertCircle, TrendingUp, Info, Plus, RotateCcw, X, Trash2, ChevronLeft, ChevronRight, Edit2, ShieldAlert, Check, Save, Star, Shield, Thermometer, TestTube2, Baby, ArrowRight, Gift, FileText, Activity } from 'lucide-react';

interface Props {
  settings: UserSettings;
  onUpdateSettings: (s: UserSettings) => void;
}

export const PrePregnancyDashboard: React.FC<Props> = ({ settings, onUpdateSettings }) => {
  const [completedTasks, setCompletedTasks] = useState<string[]>(settings.preConceptionChecklist || []);
  const [cycleDay, setCycleDay] = useState(1);
  const [daysUntilPeriod, setDaysUntilPeriod] = useState(0);
  const [conceptionChance, setConceptionChance] = useState<string>('');

  // Modals
  const [showLogModal, setShowLogModal] = useState(false); // For "Add Past Date"
  const [showHistoryModal, setShowHistoryModal] = useState(false); // For "Manage History"
  const [showConfirmStart, setShowConfirmStart] = useState(false); // For "Log Period Start" (Today)
  const [showPregnancyModal, setShowPregnancyModal] = useState(false); // For Switching Mode

  const [newPastDate, setNewPastDate] = useState('');

  // Editing State
  const [editingDate, setEditingDate] = useState<string | null>(null);
  const [editValue, setEditValue] = useState<string>('');

  // Calendar State
  const [calendarDate, setCalendarDate] = useState(new Date());

  const currentDayOfYear = Math.floor((new Date().getTime() - new Date(new Date().getFullYear(), 0, 0).getTime()) / (1000 * 60 * 60 * 24));
  const dailyTip = DAILY_TIPS_REGISTRY[currentDayOfYear % DAILY_TIPS_REGISTRY.length];

  // Helper: Parse YYYY-MM-DD to local midnight Date object
  const parseLocalYMD = (dateString: string) => {
      if (!dateString) return new Date();
      const [y, m, d] = dateString.split('-').map(Number);
      return new Date(y, m - 1, d);
  };

  // Helper: Format Date to YYYY-MM-DD local
  const formatLocalYMD = (date: Date) => {
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };

  // Helper: Get Fertility Probability & Phase Info
  const getCyclePhaseInfo = (currentDay: number, cycleLen: number, isLog: boolean) => {
      const ovulationDay = cycleLen - 14;
      const fertileStart = ovulationDay - 5;
      const fertileEnd = ovulationDay + 2;
      const diff = ovulationDay - currentDay;

      // 1. Period Phase (Actual Log)
      if (isLog) {
          return {
              phase: 'Period_Log',
              label: 'Menstruation',
              subLabel: 'Cycle Restart',
              gradient: 'from-rose-600 to-red-700',
              shadow: 'shadow-rose-600/30',
              colorClass: 'bg-rose-600',
              textClass: 'text-white',
              icon: Droplet,
              chance: '<1%'
          };
      }

      // 2. Period Phase (Expected)
      if (currentDay >= 1 && currentDay <= 5) {
          return {
              phase: 'Period_Exp',
              label: 'Expected Period',
              subLabel: 'Predicted',
              gradient: 'from-rose-400 to-rose-500',
              shadow: 'shadow-rose-400/30',
              colorClass: 'bg-rose-300 dark:bg-rose-900/60', // Lighter/Distinct
              textClass: 'text-rose-900 dark:text-rose-100',
              icon: Droplet,
              chance: '<1%'
          };
      }

      // 3. Ovulation (Peak)
      if (currentDay === ovulationDay) {
          return {
              phase: 'Ovulation',
              label: 'Ovulation Day',
              subLabel: 'Egg Release',
              gradient: 'from-purple-600 to-fuchsia-600',
              shadow: 'shadow-purple-500/30',
              colorClass: 'bg-purple-600',
              textClass: 'text-white',
              icon: Star,
              chance: '33%'
          };
      }

      // 4. Fertile Window
      if (currentDay >= fertileStart && currentDay <= fertileEnd) {
          // High Fertility (1-2 days before O)
          if (diff === 1 || diff === 2) {
              return {
                  phase: 'High',
                  label: 'High Fertility',
                  subLabel: 'Best Time to Try',
                  gradient: 'from-emerald-500 to-green-600',
                  shadow: 'shadow-emerald-500/30',
                  colorClass: 'bg-emerald-500',
                  textClass: 'text-white',
                  icon: Heart,
                  chance: diff === 1 ? '31%' : '27%'
              };
          }
          // Medium/Start of Window
          return {
              phase: 'Fertile',
              label: 'Fertile Window',
              subLabel: 'Good Chance',
              gradient: 'from-teal-400 to-teal-600',
              shadow: 'shadow-teal-500/30',
              colorClass: 'bg-teal-500',
              textClass: 'text-white',
              icon: TrendingUp,
              chance: diff > 2 ? '15-17%' : '10%'
          };
      }

      // 5. Safe / Luteal
      return {
          phase: 'Safe',
          label: 'Luteal Phase',
          subLabel: 'Low Fertility',
          gradient: 'from-blue-500 to-indigo-600',
          shadow: 'shadow-blue-500/30',
          colorClass: 'bg-blue-100 dark:bg-blue-900/50',
          textClass: 'text-blue-900 dark:text-blue-100', 
          icon: Shield,
          chance: '<1%'
      };
  };

  // --- Cycle Calculations (Medical Standard: WHO / FOGSI) ---
  useEffect(() => {
    if (settings.lmp) {
      const lmpDate = parseLocalYMD(settings.lmp);
      const today = new Date();
      today.setHours(0,0,0,0);

      const diffTime = today.getTime() - lmpDate.getTime();
      const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

      // Let's use linear day for display and logic
      const linearCycleDay = diffDays + 1;
      setCycleDay(linearCycleDay);

      // Determine chance for today
      const todayLog = (settings.periodLog || []).includes(formatLocalYMD(today));
      // For phase coloring we wrap around cycle length
      const wrappedCycleDay = ((diffDays % settings.cycleLength) + settings.cycleLength) % settings.cycleLength + 1;

      const phase = getCyclePhaseInfo(wrappedCycleDay, settings.cycleLength, todayLog);
      setConceptionChance(phase.chance);

      setDaysUntilPeriod(settings.cycleLength - linearCycleDay + 1);
    }
  }, [settings.lmp, settings.cycleLength, settings.periodLog]);

  // --- CLINICAL CYCLE ANALYSIS ALGORITHM (FOGSI/FIGO Standards) ---
  const analyzeCycleHealth = () => {
      const logs = settings.periodLog || [];
      if (logs.length < 2) {
          return { status: 'Insufficient Data', color: 'gray', advice: 'Log at least 3 periods for an accurate clinical assessment.', causes: [] };
      }

      // 1. Calculate lengths between consecutive periods
      const sortedDates = [...logs].map(d => parseLocalYMD(d)).sort((a, b) => a.getTime() - b.getTime());
      const lengths = [];
      for (let i = 0; i < sortedDates.length - 1; i++) {
          const diff = Math.ceil((sortedDates[i+1].getTime() - sortedDates[i].getTime()) / (1000 * 60 * 60 * 24));
          lengths.push(diff);
      }

      // If only 1 length available, we can only judge length, not regularity
      const avgLength = Math.round(lengths.reduce((a, b) => a + b, 0) / lengths.length);
      const minLength = Math.min(...lengths);
      const maxLength = Math.max(...lengths);
      const variation = maxLength - minLength;

      // --- CRITERIA 1: LENGTH (Normal 21-35 Days) ---
      if (avgLength < 21) {
          return {
              status: 'Polymenorrhea (Frequent Cycles)',
              color: 'red',
              advice: 'Your average cycle is shorter than 21 days. This may affect egg quality.',
              causes: ['Luteal Phase Defect', 'Anovulation', 'Stress', 'Perimenopause (if age > 35)']
          };
      }
      if (avgLength > 35) {
          return {
              status: 'Oligomenorrhea (Long Cycles)',
              color: 'red',
              advice: 'Your average cycle is longer than 35 days. This strongly suggests delayed ovulation.',
              causes: ['PCOS (Polycystic Ovarian Syndrome)', 'Thyroid Disorders', 'Hyperprolactinemia']
          };
      }

      // --- CRITERIA 2: REGULARITY (Variation < 7-9 days) ---
      // We need at least 3 logs (2 intervals) to judge regularity properly
      if (lengths.length >= 2) {
          if (variation >= 9) {
              return {
                  status: 'Irregular Cycles',
                  color: 'orange',
                  advice: `Your cycle varies by ${variation} days. This makes predicting ovulation difficult.`,
                  causes: ['Hormonal Imbalance', 'PCOS', 'Stress/Lifestyle', 'Thyroid issues']
              };
          }
      }

      return {
          status: 'Normal & Regular',
          color: 'green',
          advice: `Your cycle is consistent (${avgLength} days) and within the normal fertility range (21-35 days).`,
          causes: []
      };
  };

  const cycleAnalysis = analyzeCycleHealth();

  const toggleTask = (taskId: string) => {
      let updated;
      if (completedTasks.includes(taskId)) {
          updated = completedTasks.filter(id => id !== taskId);
      } else {
          updated = [...completedTasks, taskId];
      }
      setCompletedTasks(updated);
      onUpdateSettings({ ...settings, preConceptionChecklist: updated });
  };

  const handleLogPeriodToday = () => {
      const todayLocal = formatLocalYMD(new Date());
      const updatedLog = [todayLocal, ...(settings.periodLog || [])];
      const uniqueLog = [...new Set(updatedLog)].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

      onUpdateSettings({ 
          ...settings, 
          lmp: todayLocal, 
          periodLog: uniqueLog
      });
      setShowConfirmStart(false);
  };

  const toggleIntercourse = (dateStr: string) => {
      const currentLog = settings.intercourseLog || [];
      let updatedLog;
      if (currentLog.includes(dateStr)) {
          updatedLog = currentLog.filter(d => d !== dateStr);
      } else {
          updatedLog = [...currentLog, dateStr];
      }
      onUpdateSettings({ ...settings, intercourseLog: updatedLog });
  };

  const handleAddPastPeriod = () => {
      if(!newPastDate) return;
      const updatedLog = [newPastDate, ...(settings.periodLog || [])];
      const uniqueLog = [...new Set(updatedLog)].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

      let newLmp = settings.lmp;
      if (!newLmp || new Date(newPastDate) > new Date(newLmp)) {
          newLmp = newPastDate;
      }

      onUpdateSettings({
          ...settings,
          lmp: newLmp,
          periodLog: uniqueLog
      });
      setShowLogModal(false);
      setNewPastDate('');
  };

  const handleStartEdit = (date: string) => {
      setEditingDate(date);
      setEditValue(date);
  };

  const handleCancelEdit = () => {
      setEditingDate(null);
      setEditValue('');
  };

  const handleSaveEdit = () => {
      if (!editValue || !editingDate) return;
      const currentLog = settings.periodLog || [];
      let newLog = currentLog.filter(d => d !== editingDate && d !== editValue);
      newLog.push(editValue);
      newLog.sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
      const newLmp = newLog.length > 0 ? newLog[0] : null;
      onUpdateSettings({ ...settings, periodLog: newLog, lmp: newLmp });
      setEditingDate(null);
      setEditValue('');
  };

  const handleDeleteLog = (dateToDelete: string, e?: React.MouseEvent) => {
      e?.preventDefault();
      e?.stopPropagation();
      if (!window.confirm("Are you sure you want to delete this period entry?")) return;
      const currentLog = settings.periodLog || [];
      const updatedLog = currentLog.filter(d => d !== dateToDelete);
      let newLmp = settings.lmp;
      if (dateToDelete === settings.lmp || !updatedLog.includes(settings.lmp || '')) {
          const sorted = [...updatedLog].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
          newLmp = sorted.length > 0 ? sorted[0] : null;
      }
      onUpdateSettings({ ...settings, lmp: newLmp, periodLog: updatedLog });
  };

  const handleSwitchToPregnancy = () => {
      setShowPregnancyModal(true);
  };

  const confirmPregnancySwitch = () => {
      onUpdateSettings({
          ...settings,
          status: 'pregnant',
          isPostpartum: false,
          pregnancyLmp: settings.lmp
      });
      setShowPregnancyModal(false);
  };

  const calculatePredictedCycle = () => {
      const logs = settings.periodLog || [];
      if (logs.length < 2) return null;
      const sorted = [...logs].sort((a, b) => parseLocalYMD(a).getTime() - parseLocalYMD(b).getTime()); // Older first
      // Use logic above in analyzer, simplified here
      const recentLogs = sorted.slice(-7); 
      let totalDiff = 0;
      let count = 0;
      for(let i = 0; i < recentLogs.length - 1; i++) {
          const d1 = parseLocalYMD(recentLogs[i]);
          const d2 = parseLocalYMD(recentLogs[i+1]);
          const diffTime = Math.abs(d2.getTime() - d1.getTime());
          const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
          if(diffDays > 15 && diffDays < 50) {
              totalDiff += diffDays;
              count++;
          }
      }
      if(count === 0) return null;
      return Math.round(totalDiff / count);
  };

  const predictedCycle = calculatePredictedCycle();

  const applyPredictedCycle = () => {
      if(predictedCycle) {
          onUpdateSettings({ ...settings, cycleLength: predictedCycle });
      }
  };

  const calculateBMI = () => {
      if(settings.prePregnancyWeight && settings.heightCm) {
          const hM = settings.heightCm / 100;
          return (settings.prePregnancyWeight / (hM * hM)).toFixed(1);
      }
      return null;
  };

  const bmi = calculateBMI();
  let bmiStatus = { label: 'Unknown', color: 'text-gray-500', advice: '' };
  if(bmi) {
      const val = parseFloat(bmi);
      if(val < 18.5) bmiStatus = { label: 'Underweight', color: 'text-yellow-600', advice: 'Aim to gain a little weight to support ovulation.' };
      else if(val < 25) bmiStatus = { label: 'Normal Weight', color: 'text-green-600', advice: 'Great! Maintain this for optimal fertility.' };
      else if(val < 30) bmiStatus = { label: 'Overweight', color: 'text-orange-600', advice: 'Losing 5-10% weight can significantly boost fertility (PCOS).' };
      else bmiStatus = { label: 'Obese', color: 'text-red-600', advice: 'Consult a doctor for a safe weight loss plan before conceiving.' };
  }

  // --- Two-Week Wait / Conception Analysis Logic ---
  const analyzeConceptionPotential = () => {
      if (!settings.lmp) return null;
      const lmpDate = parseLocalYMD(settings.lmp);
      const today = new Date();
      today.setHours(0,0,0,0);

      // Current cycle logic
      const diffTime = today.getTime() - lmpDate.getTime();
      const currentCycleDays = Math.floor(diffTime / (1000 * 60 * 60 * 24)) + 1; // 1-based

      const ovulationDay = settings.cycleLength - 14;
      const fertileStart = ovulationDay - 5;
      const fertileEnd = ovulationDay + 2;

      // Only relevant if we are PAST ovulation (Luteal Phase)
      // Check 1 week post ovulation onwards
      if (currentCycleDays > ovulationDay) {

          // Check if intercourse happened during fertile window of THIS cycle
          const logs = settings.intercourseLog || [];
          let hitFertileWindow = false;

          for (let d = fertileStart; d <= fertileEnd; d++) {
              const checkDate = new Date(lmpDate);
              checkDate.setDate(checkDate.getDate() + (d - 1)); // 0-based add
              const dateStr = formatLocalYMD(checkDate);
              if (logs.includes(dateStr)) {
                  hitFertileWindow = true;
                  break;
              }
          }

          if (hitFertileWindow) {
              const nextPeriodDate = new Date(lmpDate);
              nextPeriodDate.setDate(nextPeriodDate.getDate() + settings.cycleLength);
              const testDate = new Date(nextPeriodDate);
              testDate.setDate(testDate.getDate() + 1); // Test 1 day after missed period

              return {
                  status: 'potential',
                  testDate: testDate,
                  daysPostOvulation: currentCycleDays - ovulationDay
              };
          }
      }
      return null;
  };

  const conceptionStatus = analyzeConceptionPotential();
  const daysLate = cycleDay > settings.cycleLength ? cycleDay - settings.cycleLength : 0;

  // --- Calendar Logic ---
  const renderCalendar = () => {
      const year = calendarDate.getFullYear();
      const month = calendarDate.getMonth();
      const firstDay = new Date(year, month, 1);
      const lastDay = new Date(year, month + 1, 0);
      const daysInMonth = lastDay.getDate();
      const startDayOfWeek = firstDay.getDay(); 

      const calendarDays = [];
      for (let i = 0; i < startDayOfWeek; i++) {
          calendarDays.push(<div key={`empty-${i}`} className="h-10 md:h-14"></div>);
      }

      const lmpDate = settings.lmp ? parseLocalYMD(settings.lmp) : null;
      const cycleLen = settings.cycleLength;

      for (let d = 1; d <= daysInMonth; d++) {
          const currentDayStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
          const currentDayDate = new Date(year, month, d);

          const isActualLog = (settings.periodLog || []).includes(currentDayStr);
          const isIntercourse = (settings.intercourseLog || []).includes(currentDayStr);

          let phaseInfo = null;

          if (lmpDate) {
              const diffTime = currentDayDate.getTime() - lmpDate.getTime();
              const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
              // Handle future/past cycles relative to LMP
              const rawCycleDay = ((diffDays % cycleLen) + cycleLen) % cycleLen;
              const cycleDayNum = rawCycleDay + 1;

              phaseInfo = getCyclePhaseInfo(cycleDayNum, cycleLen, isActualLog);
          }

          let bgClass = phaseInfo ? phaseInfo.colorClass : "bg-gray-50 dark:bg-white/5";
          let textClass = phaseInfo ? phaseInfo.textClass : "text-gray-700 dark:text-gray-300";
          let borderClass = "border-transparent";

          if (phaseInfo) {
              if (phaseInfo.phase === 'Period_Log') {
                  textClass = "text-white font-bold";
              }
          }

          if (isIntercourse) {
              borderClass = "border-pink-400";
          }

          calendarDays.push(
              <button 
                key={d} 
                onClick={() => toggleIntercourse(currentDayStr)}
                className={`h-12 md:h-16 rounded-lg flex flex-col items-center justify-center text-xs md:text-sm relative transition-all border ${borderClass} ${bgClass} ${currentDayStr === formatLocalYMD(new Date()) ? 'ring-2 ring-pink-500 z-10 shadow-lg' : 'hover:opacity-80'}`}
              >
                  <span className={textClass + " font-bold"}>{d}</span>
                  {isActualLog && <div className="w-1.5 h-1.5 bg-white rounded-full mt-1"></div>}

                  {/* Phase Info */}
                  {phaseInfo && phaseInfo.chance !== '<1%' && !isActualLog && (
                      <span className={`text-[8px] md:text-[10px] uppercase font-bold mt-0.5 ${textClass}`}>
                          {phaseInfo.chance}
                      </span>
                  )}

                  {/* Intercourse Marker */}
                  {isIntercourse && (
                      <Heart size={12} className="fill-pink-500 text-pink-500 absolute top-1 right-1 animate-pulse" />
                  )}

                  {/* Ovulation Star */}
                  {phaseInfo?.phase === 'Ovulation' && !isIntercourse && (
                      <Star size={10} className="fill-yellow-400 text-yellow-400 absolute top-1 right-1" />
                  )}
              </button>
          );
      }

      return (
          <div className="space-y-4">
              <div className="flex items-center justify-between">
                  <h4 className="font-bold text-lg text-gray-800 dark:text-white">
                      {calendarDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
                  </h4>
                  <div className="flex gap-2">
                      <button onClick={() => setCalendarDate(new Date(calendarDate.setMonth(calendarDate.getMonth() - 1)))} className="p-2 hover:bg-gray-100 dark:hover:bg-white/10 rounded-full"><ChevronLeft size={20} /></button>
                      <button onClick={() => setCalendarDate(new Date())} className="text-xs font-bold text-pink-600 px-2">Today</button>
                      <button onClick={() => setCalendarDate(new Date(calendarDate.setMonth(calendarDate.getMonth() + 1)))} className="p-2 hover:bg-gray-100 dark:hover:bg-white/10 rounded-full"><ChevronRight size={20} /></button>
                  </div>
              </div>
              <div className="grid grid-cols-7 gap-1 md:gap-2 text-center">
                  {['S','M','T','W','T','F','S'].map((day, i) => (
                      <div key={i} className="text-xs font-bold text-gray-400 py-1">{day}</div>
                  ))}
                  {calendarDays}
              </div>

              {/* Enhanced Legend */}
              <div className="flex flex-wrap gap-3 text-xs justify-center pt-2 bg-gray-50 dark:bg-indigo-900/10 p-3 rounded-xl border border-gray-100 dark:border-indigo-900/30">
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-rose-600 rounded"></div> Period (Log)</div>
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-purple-600 rounded"></div> Ovulation</div>
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-emerald-500 rounded"></div> High Fertility</div>
                  <div className="flex items-center gap-1"><div className="w-3 h-3 bg-teal-500 rounded"></div> Fertile</div>
                  <div className="flex items-center gap-1"><Heart size={10} className="fill-pink-500 text-pink-500"/> Activity</div>
              </div>
          </div>
      );
  };

  const wrappedCycleDay = ((cycleDay - 1) % settings.cycleLength) + 1; // Wrap for color logic
  const currentPhaseInfo = getCyclePhaseInfo(wrappedCycleDay, settings.cycleLength, (settings.periodLog || []).includes(formatLocalYMD(new Date())));
  const isTodayIntercourse = (settings.intercourseLog || []).includes(formatLocalYMD(new Date()));

  // --- High Risk History Check ---
  const obs = settings.obstetricHistory;
  const hasHistoryRisk = (obs?.lastBabyCongenitalDefect || false) || 
                         (obs?.abortionsT1 || 0) >= 2 || 
                         (obs?.abortionsT2 || 0) >= 1;

  return (
    <div className="space-y-8 animate-fade-in pb-10">

      {/* Daily Tip Section */}
      <div className="bg-blue-50 dark:bg-blue-900/10 p-6 rounded-3xl border border-blue-100 dark:border-blue-900/30">
          <h4 className="font-bold text-blue-800 dark:text-blue-300 mb-2 flex items-center gap-2">
              <Activity size={18} /> Daily Tip
          </h4>
          <p className="text-sm text-blue-700 dark:text-blue-400">
              {dailyTip}
          </p>
      </div>

      {/* Conception Alert Block (Restored) */}
      {conceptionStatus && (
          <div className="bg-gradient-to-r from-purple-500 to-indigo-600 rounded-3xl p-6 text-white shadow-xl mb-6 animate-fade-in">
              <div className="flex items-start gap-4">
                  <div className="p-3 bg-white/20 rounded-full shrink-0">
                      <Star size={32} />
                  </div>
                  <div className="flex-1">
                      <h3 className="text-xl font-bold">Potential Conception Detected</h3>
                      <p className="opacity-90 text-sm mt-1">
                          You logged activity during your fertile window this cycle!
                      </p>

                      <div className="bg-white/10 rounded-xl p-4 mt-3 text-xs space-y-2 border border-white/20">
                          <p className="font-bold uppercase opacity-80 flex items-center gap-2">
                              <TestTube2 size={12}/> Testing Recommendation:
                          </p>
                          <p>
                              Wait until <strong>{conceptionStatus.testDate.toDateString()}</strong> to take a home pregnancy test for accurate results.
                          </p>
                          <p className="italic opacity-70 mt-1">
                              (Testing too early can show a false negative due to low hCG levels).
                          </p>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Missed Period Alert & Mode Switcher */}
      {daysLate > 0 && (
          <div className="bg-gradient-to-r from-pink-500 to-rose-500 rounded-3xl p-6 text-white shadow-xl animate-pulse-slow">
              <div className="flex flex-col md:flex-row items-start gap-4">
                  <div className="p-3 bg-white/20 rounded-full shrink-0">
                      <Baby size={32} />
                  </div>
                  <div className="flex-1">
                      <h3 className="text-xl font-bold">Period Late by {daysLate} Days?</h3>
                      <p className="opacity-90 text-sm mt-1">
                          If your home pregnancy test is positive, congratulations! You can switch modes now to start tracking your baby's journey.
                      </p>

                      <button 
                          onClick={handleSwitchToPregnancy}
                          className="mt-4 w-full py-3 bg-white text-pink-600 font-bold rounded-xl shadow-lg hover:bg-pink-50 transition-colors flex items-center justify-center gap-2"
                      >
                          <CheckCircle2 size={18} /> Yes, I'm Pregnant! Switch Mode
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Hero: Cycle Status */}
      <div className={`rounded-3xl p-8 text-white shadow-xl relative overflow-hidden transition-all duration-500 bg-gradient-to-br ${currentPhaseInfo.gradient} ${currentPhaseInfo.shadow}`}>
         <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-10 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl pointer-events-none"></div>

         <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
            <div className="text-center md:text-left">
                <div className="flex items-center justify-center md:justify-start gap-2 mb-2 opacity-90">
                    <Calendar size={20} />
                    <span className="text-sm font-bold uppercase tracking-wider">Cycle Day {cycleDay}</span>
                </div>
                <h2 className="text-4xl font-bold mb-2">
                    {daysLate > 0 ? "Period Missed" : currentPhaseInfo.label}
                </h2>
                <p className="text-lg opacity-90">
                    {daysLate > 0 
                        ? `${daysLate} days past expected date.`
                        : currentPhaseInfo.phase === 'Safe' 
                            ? `Next period in approx ${daysUntilPeriod} days.`
                            : `Conception Chance: ${currentPhaseInfo.chance}`
                    }
                </p>

                {currentPhaseInfo.phase !== 'Safe' && !currentPhaseInfo.phase.startsWith('Period') && daysLate <= 0 && (
                    <div className="mt-4 inline-flex items-center gap-2 bg-white/20 backdrop-blur-md px-4 py-2 rounded-full border border-white/20">
                        <currentPhaseInfo.icon size={16} fill="white" className="animate-pulse" />
                        <span className="font-bold text-sm">
                            {currentPhaseInfo.subLabel}
                        </span>
                    </div>
                )}
            </div>

            <div className="flex flex-col gap-3 w-full md:w-auto">
                <button 
                    onClick={() => toggleIntercourse(formatLocalYMD(new Date()))}
                    className={`group relative px-8 py-3 font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3 overflow-hidden ${isTodayIntercourse ? 'bg-pink-100 text-pink-700' : 'bg-white text-gray-800'}`}
                >
                    <Heart size={20} className={isTodayIntercourse ? "fill-pink-600 text-pink-600" : "text-gray-400"} />
                    <span className="relative z-10">{isTodayIntercourse ? 'Activity Logged' : 'Log Activity'}</span>
                </button>
                <button 
                    onClick={() => setShowConfirmStart(true)}
                    className="px-8 py-3 bg-white/20 hover:bg-white/30 backdrop-blur-sm text-white font-bold rounded-2xl border border-white/30 transition-all flex items-center justify-center gap-2"
                >
                    <Droplet size={20} fill="currentColor" /> Period Started
                </button>
            </div>
         </div>
      </div>

      {/* Period History & Prediction */}
      <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 p-6">
          <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2">
                  <Calendar size={20} /> Period History
              </h3>
              <div className="flex gap-2">
                  <button onClick={() => setShowHistoryModal(true)} className="text-sm text-gray-500 font-bold flex items-center gap-1 hover:bg-gray-100 dark:hover:bg-white/10 px-3 py-1.5 rounded-lg transition-colors">
                      <Edit2 size={14} /> Manage
                  </button>
                  <button onClick={() => setShowLogModal(!showLogModal)} className="text-sm text-teal-600 font-bold flex items-center gap-1 hover:bg-teal-50 px-3 py-1.5 rounded-lg transition-colors">
                      <Plus size={16} /> Add Date
                  </button>
              </div>
          </div>

          {/* Add Past Date Logic */}
          {showLogModal && (
              <div className="mb-4 p-4 bg-gray-50 dark:bg-indigo-900/20 rounded-xl flex gap-2 items-center animate-fade-in">
                  <input 
                    type="date" 
                    value={newPastDate} 
                    onChange={(e) => setNewPastDate(e.target.value)} 
                    max={new Date().toISOString().split('T')[0]}
                    className="flex-1 px-3 py-2 rounded-lg border border-gray-200 dark:border-indigo-700 dark:bg-deep-bg dark:text-white"
                  />
                  <Button onClick={handleAddPastPeriod} disabled={!newPastDate} className="text-sm">Add</Button>
              </div>
          )}

          {/* Manage History Modal with Edit Capability */}
          {showHistoryModal && (
              <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
                  <div className="bg-white dark:bg-deep-card rounded-3xl p-6 shadow-2xl max-w-sm w-full border border-gray-200 dark:border-indigo-800 flex flex-col max-h-[80vh]">
                      <div className="flex justify-between items-center mb-4">
                          <h3 className="text-xl font-bold text-gray-800 dark:text-white">Edit History</h3>
                          <button onClick={() => setShowHistoryModal(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"><X size={24} /></button>
                      </div>
                      <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2 mb-4">
                          {settings.periodLog && settings.periodLog.length > 0 ? (
                              settings.periodLog.map((date, i) => (
                                  <div key={i} className="flex items-center justify-between p-3 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border border-gray-100 dark:border-indigo-900/30">
                                      {editingDate === date ? (
                                          <div className="flex items-center gap-2 w-full">
                                              <input 
                                                type="date" 
                                                value={editValue} 
                                                onChange={(e) => setEditValue(e.target.value)}
                                                max={new Date().toISOString().split('T')[0]}
                                                className="flex-1 px-2 py-1 rounded border border-gray-300 dark:border-indigo-600 dark:bg-deep-bg dark:text-white text-sm"
                                              />
                                              <button onClick={handleSaveEdit} className="p-1 text-green-600 hover:bg-green-50 dark:hover:bg-green-900/20 rounded">
                                                  <Check size={18} />
                                              </button>
                                              <button onClick={handleCancelEdit} className="p-1 text-gray-500 hover:bg-gray-100 dark:hover:bg-indigo-900/30 rounded">
                                                  <X size={18} />
                                              </button>
                                          </div>
                                      ) : (
                                          <>
                                            <div className="text-gray-800 dark:text-white font-medium">
                                                {parseLocalYMD(date).toLocaleDateString(undefined, { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' })}
                                            </div>
                                            <div className="flex items-center gap-1">
                                                <button 
                                                    onClick={() => handleStartEdit(date)}
                                                    className="p-2 text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-colors"
                                                    title="Edit Date"
                                                >
                                                    <Edit2 size={16} />
                                                </button>
                                                <button 
                                                    onClick={(e) => handleDeleteLog(date, e)} 
                                                    className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors"
                                                    title="Delete Date"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                          </>
                                      )}
                                  </div>
                              ))
                          ) : (
                              <p className="text-center text-gray-400 py-4">No history to edit.</p>
                          )}
                      </div>
                      <Button variant="secondary" onClick={() => setShowHistoryModal(false)}>Close</Button>
                  </div>
              </div>
          )}

          {predictedCycle && predictedCycle !== settings.cycleLength && (
              <div className="mb-4 p-3 bg-blue-50 dark:bg-blue-900/10 rounded-xl border border-blue-100 dark:border-blue-900/30 flex items-center justify-between">
                  <div className="text-sm text-blue-800 dark:text-blue-300">
                      <strong>AI Insight:</strong> Based on your last 6 months, your average cycle is {predictedCycle} days.
                  </div>
                  <button onClick={applyPredictedCycle} className="text-xs bg-blue-100 dark:bg-blue-800 text-blue-700 dark:text-blue-200 px-3 py-1.5 rounded-lg font-bold flex items-center gap-1 hover:bg-blue-200 transition-colors">
                      <RotateCcw size={12} /> Apply
                  </button>
              </div>
          )}

          <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-thin">
              {settings.periodLog && settings.periodLog.length > 0 ? (
                  settings.periodLog.slice(0, 6).map((date, i) => {
                      const d = parseLocalYMD(date);
                      return (
                        <div key={i} className="flex-shrink-0 w-20 p-3 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border border-gray-100 dark:border-indigo-900/30 text-center flex flex-col justify-center">
                            <div className="text-xs text-gray-500 dark:text-gray-400 font-bold uppercase">{d.toLocaleString('default', { month: 'short' })}</div>
                            <div className="text-xl font-bold text-gray-800 dark:text-white">{d.getDate()}</div>
                        </div>
                      );
                  })
              ) : (
                  <p className="text-sm text-gray-400 w-full text-center py-4">No history yet. Log your first period!</p>
              )}
          </div>
      </div>

      {/* Calendar View */}
      <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 p-6">
          <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
              <Calendar size={20} className="text-pink-600" /> Cycle Calendar
          </h3>
          <p className="text-xs text-gray-500 dark:text-gray-400 mb-4 -mt-2">Tap a date to log activity/intercourse</p>
          {renderCalendar()}
      </div>
    </div>
  );
};
